import * as React from 'react';
import clsx from 'clsx';
import { ListCaption } from '../../shared/components/list';
import { cssTypographyCaption0 } from '../../stylex';
import { useTransferContext } from '../hooks/TransferContext';
import { forwardHTMLRef } from '../../util/forwardRef';
import { sxListCaption, sxOption } from '../sx';

export const TransferListCaption = forwardHTMLRef<unknown, 'div'>((props, ref) => {
  const { className, children, ...htmlProps } = props;
  const { cssScope } = useTransferContext();

  return (
    <ListCaption
      className={clsx(className, cssScope('__caption'))}
      sx={[cssTypographyCaption0, sxListCaption, sxOption]}
      {...htmlProps}
      ref={ref}
    >
      {children}
    </ListCaption>
  );
});
